package ua.university.sms.model.entity;
import jakarta.persistence.*;import java.util.*;
@Entity @Table(name="teachers") public class Teacher{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@Column(name="full_name",nullable=false,length=200) private String fullName;@Column(nullable=false,unique=true) private String email;@Column(nullable=false,length=150) private String department;@OneToMany(mappedBy="teacher") private List<Course> courses=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getFullName(){return fullName;}public void setFullName(String fullName){this.fullName=fullName;}public String getEmail(){return email;}public void setEmail(String email){this.email=email;}public String getDepartment(){return department;}public void setDepartment(String department){this.department=department;}public List<Course> getCourses(){return courses;}}
